interface TaskItem {
  /** 显示文本 */
  label: string;
  /** 任务状态 */
  status: "pending" | "in_progress" | "completed" | "failed" | "cancelled";
  /** 可选的详情/证据 */
  detail?: string;
  /** 可选的子项 */
  children?: TaskItem[];
