}

// ── 核心数据模型 ─────────────────────────────────────

/** LLM Judge 产出的单条进化建议 */
export interface EvolutionSuggestion {
	/** UUID */
	id: string;
	/** 建议目标类型 */
	target: "claude-md" | "skill";
	/** 要修改的文件绝对路径 */
	targetPath: string;
	/** 严重程度 */
	severity: "high" | "medium" | "low";
	/** 0-1 置信度 */
	confidence: number;
	/** 建议标题 */
	title: string;
	/** 建议内容描述 */
	description: string;
	/** 数据支撑说明 */
	rationale: string;
	/** 自然语言修改指令，供 LLM 执行时参考 */
